startingCSS:
.card {
  position: relative;
  width: 320px;
  border-radius: 10px;
  overflow: hidden;
}

.photo {
  width: 100%;
  height: 180px;
  object-fit: cover;
  display: block;
}

.overlay {
  position: absolute;
  /* Replace these four lines with inset: 0 */
  top: 0;
  right: 0;
  bottom: 0;
  left: 0;
  background: linear-gradient(to top, rgba(0,0,0,0.8) 0%, transparent 60%);
  display: flex;
  flex-direction: column;
  justify-content: flex-end;
  padding: 1rem;
  color: white;
}

.overlay strong {
  display: block;
  font-size: 0.95rem;
  margin-bottom: 0.2rem;
}

.overlay p {
  margin: 0;
  font-size: 0.75rem;
  opacity: 0.85;
}
